import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Flushable;
import java.io.IOException;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterFlushTest {

    private CSVFormat format;
    private Appendable appendable;

    @BeforeEach
    void setUp() {
        format = mock(CSVFormat.class);
    }

    @Test
    void flush_withFlushableOut_invokesFlush() throws IOException {
        Flushable flushableOut = mock(Flushable.class);
        // CSVPrinter expects Appendable, Flushable is not Appendable, so create a mock that implements both
        Appendable flushableAppendable = mock(Appendable.class, withSettings().extraInterfaces(Flushable.class));
        when((Flushable) flushableAppendable).thenReturn(flushableOut);

        CSVPrinter printer = new CSVPrinter(flushableAppendable, format);

        printer.flush();

        verify((Flushable) flushableAppendable).flush();
    }

    @Test
    void flush_withNonFlushableOut_doesNotThrow() throws IOException {
        appendable = mock(Appendable.class);
        CSVPrinter printer = new CSVPrinter(appendable, format);

        assertDoesNotThrow(() -> printer.flush());

        // No flush method to verify since appendable is not flushable
        verifyNoMoreInteractions(appendable);
    }
}
